JSExample.Code:
 (function () {
   var workbook = Api.GetWorkbook();
   var logSheet = workbook.GetSheet("log");
    if (!logSheet) return;

  // Эмуляция End(xlUp)
  var lastRow = 1;
  for (var r = 1; r <= 5000; r++) {
      var val = logSheet.GetRange("A" + r).GetValue();
      if (val === "" || val === null) {
          lastRow = r;
          break;
      }
  }

  logSheet.GetRange("A" + lastRow).SetValue(new Date().toLocaleString());
  // Имя пользователя через системную заглушку или SQLite
  logSheet.GetRange("B" + lastRow).SetValue("User");
})();
